<?php namespace App\Repositories\Hr;use App\Repositories\BaseRepository;use App\Models\Hr\Department;use Illuminate\Database\Eloquent\Collection;class DepartmentRepository extends BaseRepository{    public function __construct(Department $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByName(string $name): ?Department    {        return $this->query()->where('name', $name)->first();    }    public function findByCode(string $code): ?Department    {        return $this->query()->where('code', $code)->first();    }    public function getActiveDepartments(): Collection    {        return $this->query()->where('is_active', true)->get();    }    public function getDepartmentWithEmployees(int $departmentId): ?Department    {        return $this->query()->with('employees')->findOrFail($departmentId);    }    public function searchDepartments(string $keyword): Collection    {        return $this->query()->where('name', 'like', "%{$keyword}%")->orWhere('code', 'like', "%{$keyword}%")->orWhere('description', 'like', "%{$keyword}%")->get();    }    public function countEmployeesByDepartment(): Collection    {        return $this->query()->withCount('employees')->get();    }    public function getByHeadOfDepartment(int $employeeId): ?Department    {        return $this->query()->where('head_of_department_id', $employeeId)->first();    }}